def max_profit(prices):
    min_p, max_f = float('inf'), 0
    for p in prices:
        min_p = min(min_p, p)
        max_f = max(max_f, p - min_p)
    return max_f

if __name__ == "__main__":
    prices = [7, 1, 5, 3, 6, 4]
    print(f"Max Profit: {max_profit(prices)}")
